<head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <title>ERA 行动模块 - 维奥莱塔定制版</title>
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css">
    <style>
        /* 动画效果定义 */
        @keyframes fadeIn {
            from { opacity: 0; transform: translateY(-15px); }
            to { opacity: 1; transform: translateY(0); }
        }

        @keyframes pulse-glow {
            0% { box-shadow: 0 10px 25px rgba(100, 0, 0, 0.15); }
            50% { box-shadow: 0 15px 30px rgba(211, 47, 47, 0.25); }
            100% { box-shadow: 0 10px 25px rgba(100, 0, 0, 0.15); }
        }

        /* 基础样式 */
        body {
            font-family: 'Segoe UI', 'Microsoft YaHei', sans-serif;
            margin: 0;
            padding: 0;
            background-color: transparent;
            min-height: 20vh;
            min-width: 200px;
            overflow: auto; /* 遵循规则: 禁止hidden */
            display: flex;
            justify-content: center;
            align-items: center;
        }

        /* 整体容器 */
        .era-actions-container {
            width: 100%;
            margin: 15px;
            padding: 20px clamp(15px, 4vw, 25px);
            background: linear-gradient(145deg, #fff0f5 0%, #ffe4e1 100%); /* 浅粉色渐变背景 */
            border-radius: 16px;
            border: 1px solid #ffb6c1;
            animation: fadeIn 0.8s cubic-bezier(0.25, 0.46, 0.45, 0.94) both, pulse-glow 3s infinite ease-in-out;
            box-sizing: border-box;
        }

        /* 标题行容器 - 已修改为居中对齐 */
        .era-actions-header {
            display: flex;
            justify-content: center; /* 移除左右元素后居中 */
            align-items: center;
            margin-bottom: 20px;
            position: relative;
        }

        /* 装饰性线条 - 增加美感 */
        .header-line {
            height: 2px;
            background: linear-gradient(to right, transparent, #ff80ab, transparent);
            width: 100%;
            position: absolute;
            bottom: -8px;
            opacity: 0.6;
        }

        /* 标题样式 */
        .era-actions-title {
            text-align: center;
            font-weight: 700;
            color: #c62828; /* 深红色文字 */
            margin: 0;
            font-size: clamp(1.1rem, 4.5vw, 1.3rem);
            text-shadow: 1px 1px 2px rgba(255, 255, 255, 0.8);
            letter-spacing: 2px;
        }

        /* 2x2 按钮网格容器 */
        .era-action-buttons {
            display: grid;
            grid-template-columns: repeat(2, 1fr);
            gap: clamp(12px, 3.5vw, 18px);
        }

        /* 按钮样式 */
        .era-action-btn {
            position: relative;
            padding: clamp(12px, 4vw, 16px) 10px;
            font-size: clamp(0.8rem, 3.5vw, 0.95rem);
            font-weight: 600;
            color: #b71c1c;
            background-color: rgba(255, 255, 255, 0.85);
            border: 1px solid #ffcdd2;
            border-radius: 12px;
            cursor: pointer;
            transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
            text-align: center;
            overflow-wrap: break-word;
            display: flex;
            justify-content: center;
            align-items: center;
            box-shadow: 0 2px 5px rgba(0,0,0,0.05);
        }

        /* 按钮交互效果 */
        .era-action-btn:hover {
            background-color: #fff;
            color: #d50000;
            border-color: #ef9a9a;
            transform: translateY(-3px);
            box-shadow: 0 5px 15px rgba(211, 47, 47, 0.15);
        }

        .era-action-btn:active {
            transform: translateY(-1px);
            box-shadow: 0 2px 5px rgba(211, 47, 47, 0.1);
            background-color: #ffEBEE;
        }

        /* 按钮内的图标间距 */
        .era-action-btn i {
            margin-right: 6px;
            font-size: 0.9em;
            opacity: 0.8;
        }
    </style>
</head>
<body>

    <div class="era-actions-container">
        <div class="era-actions-header">
            <h4 class="era-actions-title">
                <i class="fa-solid fa-star-of-david" style="font-size: 0.8em; color: #ef5350;"></i>
                行动选项
                <i class="fa-solid fa-star-of-david" style="font-size: 0.8em; color: #ef5350;"></i>
            </h4>
            <div class="header-line"></div>
        </div>

        <div class="era-action-buttons">
            <button class="era-action-btn">$1</button>
            <button class="era-action-btn">$2</button>
            <button class="era-action-btn">$3</button>
            <button class="era-action-btn">$4</button>
        </div>
    </div>

    <script>
        document.addEventListener('DOMContentLoaded', () => {
            /**
             * 发送指令到 SillyTavern
             * @param {string} text - 待发送文本
             */
            const handleSend = (text) => {
                try {
                    // 尝试定位 SillyTavern 的输入框
                    const inputArea = window.parent.document.querySelector('#send_textarea');
                    if (inputArea) {
                        // 追加或设置文本
                        const newText = inputArea.value.trim().length > 0 ? '\n' + text : text;
                        inputArea.value += (inputArea.value.trim().length > 0 ? '\n' : '') + text;

                        // 触发输入事件以通知应用更新状态
                        inputArea.dispatchEvent(new Event('input', { bubbles: true }));

                        // 可选：自动点击发送按钮 (取消注释以启用)
                        // const sendBtn = window.parent.document.querySelector('#send_butt');
                        // if (sendBtn) sendBtn.click();
                    }
                } catch (error) {
                    console.warn('SillyTavern UI 链接失败:', error);
                    // 降级处理：仅在控制台输出或复制到剪贴板
                }
            };

            // 绑定按钮事件
            document.querySelectorAll('.era-action-btn').forEach(btn => {
                btn.addEventListener('click', function() {
                    // 获取按钮文本，移除可能存在的图标HTML标签，只保留文字
                    const text = this.innerText.trim();
                    if(text) handleSend(text);

                    // 点击反馈动画
                    this.style.transform = 'scale(0.95)';
                    setTimeout(() => this.style.transform = '', 150);
                });
            });
        });
    </script>
</body>
</html>
